    hero_sub: '\u05de\u05e2\u05e8\u05db\u05ea RAG \u05de\u05e9\u05e4\u05d8\u05d9\u05ea \u05d0\u05d5\u05d8\u05d5\u05e0\u05d5\u05de\u05d9\u05ea \u05e2\u05dc \u05e4\u05e0\u05d9 300+ \u05ea\u05e7\u05e0\u05d5\u05ea DIFC, \u05e4\u05e1\u05d9\u05e7\u05d5\u05ea \u05d5\u05e2\u05e1\u05e7\u05d0\u05d5\u05ea &mdash; \u05de\u05d5\u05ea\u05d0\u05de\u05ea \u05dc\u05d0\u05de\u05d9\u05e0\u05d5\u05ea, \u05e4\u05d5\u05e8\u05de\u05d8\u05d9\u05dd \u05de\u05d7\u05de\u05d9\u05e8\u05d9\u05dd \u05d5\u05d4\u05e2\u05e8\u05db\u05d4 \u05e2\u05e6\u05de\u05d0\u05d9\u05ea \u05e9\u05dc 24 \u05e9\u05e2\u05d5\u05ea.',
