for (const [lang, overrides] of Object.entries(PAGE_V2_OVERRIDES)) {
  TRANSLATIONS[lang] = {
    ...(TRANSLATIONS[lang] || {}),
    ...overrides,
  };
}

const RTL_LANGS = ['ar', 'he'];
const SUPPORTED = Object.keys(TRANSLATIONS);

function applyLang(lang) {
  if (!SUPPORTED.includes(lang)) lang = 'en';
  const t = TRANSLATIONS[lang];
  const base = TRANSLATIONS.en || {};

  document.querySelectorAll('[data-i18n]').forEach(el => {
    const key = el.dataset.i18n;
    if (t[key] !== undefined) el.innerHTML = t[key];
    else if (base[key] !== undefined) el.innerHTML = base[key];
  });

  const html = document.documentElement;
  html.setAttribute('lang', lang);
  html.setAttribute('dir', RTL_LANGS.includes(lang) ? 'rtl' : 'ltr');

  document.querySelectorAll('[data-lang]').forEach(btn => {
    btn.classList.toggle('is-active', btn.dataset.lang === lang);
  });
  const badge = document.getElementById('lang-current-label');
  if (badge) badge.textContent = lang.toUpperCase();

  localStorage.setItem('lang', lang);
}

window.setLang = function (lang) {
  applyLang(lang);
  const menu = document.getElementById('lang-menu');
  if (menu) menu.hidden = true;
};

window.toggleLangMenu = function () {
  const menu = document.getElementById('lang-menu');
  if (menu) menu.hidden = !menu.hidden;
};

document.addEventListener('click', e => {
  if (!e.target.closest('.lang-picker')) {
    const menu = document.getElementById('lang-menu');
    if (menu) menu.hidden = true;
  }
});

document.addEventListener('DOMContentLoaded', () => {
  const saved = localStorage.getItem('lang');
  const browser = (navigator.language || '').split('-')[0];
  const lang = (saved && SUPPORTED.includes(saved)) ? saved
    : (SUPPORTED.includes(browser) ? browser : 'en');
  applyLang(lang);
});
